#include <stdio.h>

int main() {
  int a = 10;
  int b = 3;
  printf("Toplama: %d\n", a + b);
  printf("Çıxma: %d\n", a - b);
  printf("Vurma: %d\n", a * b);
  printf("Bölmə: %d\n", a / b);
  printf("Qalıq: %d\n", a % b);
  return 0;
}
// Output:
// Toplama: 13
// Çıxma: 7
// Vurma: 30
// Bölmə: 3
// Qalıq: 1

#include <stdio.h>

int main() {
  int x = 7;
  int y = 4;
  printf("x == y: %d\n", x == y);
  printf("x != y: %d\n", x != y);
  printf("x > y: %d\n", x > y);
  printf("x < y: %d\n", x < y);
  return 0;
}
// Output:
// x == y: 0
// x != y: 1
// x > y: 1
// x < y: 0

#include <stdio.h>

int main() {
  int x = 10;
  x += 5;
  printf("x += 5: %d\n", x);
  x -= 3;
  printf("x -= 3: %d\n", x);
  x *= 2;
  printf("x *= 2: %d\n", x);
  return 0;
}
// Output:
// x += 5: 15
// x -= 3: 12
// x *= 2: 24

